/*
╔══════════════════════════════════════════════════════════════╗
║ LESSON 02 — GROUP PHYSICAL SYSTEMS BY REAL PURPOSE           ║
╚══════════════════════════════════════════════════════════════╝

Production-floor numbers belong together because they describe one physical
system. Do not scatter line widths, roller lengths, strappers, and palletizer
positions through drawing code.
*/

// ── PRODUCTION FLOOR ─────────────────────────────────────────────────────
const PROD_DEPTH=66.5*FEET_TO_METERS;
const PROD_STAGE_W=9*FEET_TO_METERS, PROD_STAGE_D=9*FEET_TO_METERS;
const PROD_ROLLER_BED_COUNT=9, PROD_STAGE_NORTH_SHIFT=3*FEET_TO_METERS, PROD_ROLLER_SPACING=0.55*FEET_TO_METERS;
const PROD_SUD_ROLLER_LINE_INDEX=9, PROD_SUD_ROLLER_BED_W=60*INCHES_TO_METERS, PROD_SUD_CHAIN_LENGTH=40*FEET_TO_METERS;
const PROD_SUD_TURN_LINE_INDEX=10, PROD_SUD_TURN_ROLLER_BED_D=54*INCHES_TO_METERS, PROD_SUD_TURN_WEST_EXT=4*FEET_TO_METERS, PROD_SUD_TURN_CHAIN_LENGTH=80*FEET_TO_METERS;
const PROD_SUD_FRAME_T=6*INCHES_TO_METERS;
