const PROD_SUD_BOX_W=10*FEET_TO_METERS, PROD_SUD_BOX_L=6*FEET_TO_METERS, PROD_SUD_BOX_H=8*FEET_TO_METERS, PROD_SUD_BOX_OPEN_H=6.5*FEET_TO_METERS;
const PROD_SUD_OUTFEED_H=4.5*FEET_TO_METERS, PROD_SUD_OUTFEED_W=12*INCHES_TO_METERS, PROD_SUD_OUTFEED_BELT_W=8*INCHES_TO_METERS, PROD_SUD_OUTFEED_START_S=50*FEET_TO_METERS;
const PROD_SUD_LINE_GREEN_2D='#145a1f', PROD_SUD_STRAP_GREEN_2D='#228b22';
const PROD_WRAP_OFFSET=18*FEET_TO_METERS, PROD_WRAP_R=8*FEET_TO_METERS;
const PROD_LINE_X=[36.6,73.5,94.4,119.3,140.2,181.1,204.5,232.9,256.3,
                   298.25,328.0,368.7].map(ft=>ft*FEET_TO_METERS);
const PROD_Z1=AISLE_S, PROD_Z2=AISLE_S+PROD_DEPTH;
const PROD_GRP1_XL=27*FEET_TO_METERS,PROD_GRP1_XR=267*FEET_TO_METERS;
const PROD_GRP2_XL=269*FEET_TO_METERS,PROD_GRP2_XR=396*FEET_TO_METERS;
const prodStageZ=i=>PROD_Z1-(i<PROD_ROLLER_BED_COUNT?PROD_STAGE_NORTH_SHIFT:0);
const prodStageSegments=i=>i<PROD_ROLLER_BED_COUNT?2:1;
const PROD_ROLLER_BED_S=BIN_N+576*INCHES_TO_METERS+8*580*INCHES_TO_METERS;
const prodStageEnd=i=>i<PROD_ROLLER_BED_COUNT?PROD_ROLLER_BED_S:prodStageZ(i)+PROD_STAGE_D;
const PROD_PALLETIZER_PAIRS=[[1,2],[3,4],[5,6],[7,8]];
const PROD_PALLETIZER_W=8*FEET_TO_METERS, PROD_PALLETIZER_OPEN_W=4*FEET_TO_METERS, PROD_PALLETIZER_D=8*FEET_TO_METERS;
const PROD_PALLETIZER_N=prodStageZ(1)-4*FEET_TO_METERS, PROD_PALLETIZER_S=PROD_PALLETIZER_N+PROD_PALLETIZER_D;
// Extra dispenser: Line 1 south end, directly against the west side of the line.
