const WH23_DIV_X=WH2A_EAST_FLOOR_BINS_XR;
const WH23_VOID_W=16*INCHES_TO_METERS;
const WH23_WALL={x:WH23_DIV_X+WH23_VOID_W/2,zN:J_ZS,zS:496*FEET_TO_METERS,w:WH23_VOID_W};
