const WH3_FLOOR_BINS_XL=WH23_DIV_X+WH23_VOID_W+WH3_WALK_W, WH3_FLOOR_BINS_XR=WH3_FLOOR_BINS_XL+52*FEET_TO_METERS;
const WH3_FLOOR_BINS2_XL=WH3_FLOOR_BINS_XR+18*FEET_TO_METERS, WH3_FLOOR_BINS2_XR=WH3_FLOOR_BINS2_XL+52*FEET_TO_METERS;
const WH3_FLOOR_BINS3_XL=WH3_FLOOR_BINS2_XR+18*FEET_TO_METERS, WH3_FLOOR_BINS3_XR=WH3_FLOOR_BINS3_XL+52*FEET_TO_METERS;
const WH3_FLOOR_BINS4_XR=WH3_FLOOR_BINS2_XR, WH3_FLOOR_BINS4_XL=WH3_FLOOR_BINS4_XR-26*FEET_TO_METERS;
const WH3_FLOOR_BINS5_XR=WH3_FLOOR_BINS4_XL, WH3_FLOOR_BINS5_XL=WH3_FLOOR_BINS5_XR-26*FEET_TO_METERS;
const WH3_FLOOR_BINS6_XR=WH3_FLOOR_BINS5_XL-18*FEET_TO_METERS, WH3_FLOOR_BINS6_XL=WH3_FLOOR_BINS6_XR-52*FEET_TO_METERS;
PLANT_WIDTH_METERS=WH3_FLOOR_BINS3_XR+WH3_WALK_W;
PLANT_DEPTH_METERS=(BIN_N+576*INCHES_TO_METERS)+17*580*INCHES_TO_METERS-6*INCHES_TO_METERS+6*FEET_TO_METERS;
PLANT_REGIONS.WH3_R=PLANT_WIDTH_METERS;
// Guardrail west of the added Line 1 pallet dispenser: 2ft west, starts 16ft north, stops 40ft from south wall.
const PROD_LINE1_WEST_GUARDRAIL={
  x:PROD_LINE1_WEST_PALLETIZER.x0-2*FEET_TO_METERS,
  z0:PROD_LINE1_WEST_PALLETIZER.z0-16*FEET_TO_METERS,
  z1:PLANT_DEPTH_METERS-40*FEET_TO_METERS
};

// HR offices: exterior west-wall attachment, 40ft E-W depth.
const HR_OFFICE_EW=45*FEET_TO_METERS;
const HR_OFFICE_IMG_W=221, HR_OFFICE_IMG_H=1523;
const HR_OFFICE_NS=HR_OFFICE_EW*(HR_OFFICE_IMG_H/HR_OFFICE_IMG_W);
// Exterior west-wall doorway and patio near the western-most pallet dispenser.
// Doorway is on the west plant wall, centered on the south line of the added west pallet dispenser.
// Patio begins 2ft north of that line, runs 30ft west outside the building, and extends 80ft south.
const WEST_PATIO_DOOR_W=4*FEET_TO_METERS, WEST_PATIO_DOOR_H=8*FEET_TO_METERS;
const WEST_PATIO_DOOR_Z=PROD_LINE1_WEST_PALLETIZER.z1;
const WEST_PATIO={
  x0:-22.5*FEET_TO_METERS,
  x1:0,
  z0:WEST_PATIO_DOOR_Z-2*FEET_TO_METERS,
  z1:WEST_PATIO_DOOR_Z-2*FEET_TO_METERS+60*FEET_TO_METERS
};
const HR_OFFICE={
  // Offset west by one 8-inch wall thickness so the HR east wall
  // touches the plant wall instead of occupying the same centerline.
  x0:-HR_OFFICE_EW-8*INCHES_TO_METERS,
  x1:-8*INCHES_TO_METERS,
  // Shifted south: HR office north wall starts about 30ft south of the patio south edge.
  z0:WEST_PATIO.z1+30*FEET_TO_METERS,
  z1:WEST_PATIO.z1+30*FEET_TO_METERS+HR_OFFICE_NS
};
// HR north conference room: full E-W width, N-S depth is 2/3 of the HR E-W width.
const HR_CONFERENCE={
  x0:HR_OFFICE.x0,
  x1:HR_OFFICE.x1,
  z0:HR_OFFICE.z0,
  z1:HR_OFFICE.z0 + HR_OFFICE_EW*(2/3),
  doorW:4*FEET_TO_METERS
};
HR_CONFERENCE.doorX0=(HR_CONFERENCE.x0+HR_CONFERENCE.x1)/2-HR_CONFERENCE.doorW/2;
HR_CONFERENCE.doorX1=(HR_CONFERENCE.x0+HR_CONFERENCE.x1)/2+HR_CONFERENCE.doorW/2;

// HR office run rebuilt from user pixel measurements.
// Scale: 2.95 px = 1 ft.
// Pixel anchors:
// - plant/HR line to outside west HR wall = 120 px
// - plant/HR line to west wall of these east-side offices = 46 px
// - N/S wall centerlines from outside north HR wall: 100,115,181,235,271,327 px
// - last office outside south wall = 367 px
const HR_MEASURE_PX_PER_FT=2.95;
const HR_OFFICE_RUN={
  x1:HR_OFFICE.x1,
  // West wall of office run is 46 px west of the plant/HR wall.
  x0:HR_OFFICE.x1-(46/2.95)*FEET_TO_METERS,
  conferenceSouth:HR_OFFICE.z0+(100/2.95)*FEET_TO_METERS,
  closetSouth:HR_OFFICE.z0+(115/2.95)*FEET_TO_METERS,
  oval1South:HR_OFFICE.z0+(181/2.95)*FEET_TO_METERS,
  oval2South:HR_OFFICE.z0+(235/2.95)*FEET_TO_METERS,
  smallSouth:HR_OFFICE.z0+(271/2.95)*FEET_TO_METERS,
  secondLastCenter:HR_OFFICE.z0+(327/2.95)*FEET_TO_METERS,
  lastOfficeSouth:HR_OFFICE.z0+(367/2.95)*FEET_TO_METERS,
  plantDoorW:6*FEET_TO_METERS,
  glassWallH:8*FEET_TO_METERS,
  frontDoorW:3*FEET_TO_METERS,
  room3DoorW:4*FEET_TO_METERS,
  southDoorW:4*FEET_TO_METERS
};
// Override the conference room south wall to the measured 100px centerline.
HR_CONFERENCE.z1=HR_OFFICE_RUN.conferenceSouth;
HR_CONFERENCE.doorX0=(HR_CONFERENCE.x0+HR_CONFERENCE.x1)/2-HR_CONFERENCE.doorW/2;
HR_CONFERENCE.doorX1=(HR_CONFERENCE.x0+HR_CONFERENCE.x1)/2+HR_CONFERENCE.doorW/2;

// The measured east-side run starts immediately south of the conference room.
HR_OFFICE_RUN.z0=HR_CONFERENCE.z1;
HR_OFFICE_RUN.closet={x0:HR_OFFICE_RUN.x0,x1:HR_OFFICE_RUN.x1,z0:HR_OFFICE_RUN.z0,z1:HR_OFFICE_RUN.closetSouth};
HR_OFFICE_RUN.oval1={x0:HR_OFFICE_RUN.x0,x1:HR_OFFICE_RUN.x1,z0:HR_OFFICE_RUN.closet.z1,z1:HR_OFFICE_RUN.oval1South};
HR_OFFICE_RUN.oval2={x0:HR_OFFICE_RUN.x0,x1:HR_OFFICE_RUN.x1,z0:HR_OFFICE_RUN.oval1.z1,z1:HR_OFFICE_RUN.oval2South};
HR_OFFICE_RUN.small={x0:HR_OFFICE_RUN.x0,x1:HR_OFFICE_RUN.x1,z0:HR_OFFICE_RUN.oval2.z1,z1:HR_OFFICE_RUN.smallSouth};
// Use 327px as the centerline of the second-to-last room.
// Last room ends at 367px. The divider between second-to-last and last is halfway between 327px and 367px.
HR_OFFICE_RUN.secondLast={x0:HR_OFFICE_RUN.x0,x1:HR_OFFICE_RUN.x1,z0:HR_OFFICE_RUN.small.z1,z1:HR_OFFICE.z0+(323.5/2.95)*FEET_TO_METERS};
HR_OFFICE_RUN.last={x0:HR_OFFICE_RUN.x0,x1:HR_OFFICE_RUN.x1,z0:HR_OFFICE_RUN.secondLast.z1,z1:HR_OFFICE_RUN.lastOfficeSouth};
HR_OFFICE_RUN.plantDoorZ0=HR_OFFICE_RUN.lastOfficeSouth+0.5*FEET_TO_METERS;
HR_OFFICE_RUN.plantDoorZ1=HR_OFFICE_RUN.plantDoorZ0+HR_OFFICE_RUN.plantDoorW;

// Door locations requested from north to south.
HR_OFFICE_RUN.closetDoorZ=(HR_OFFICE_RUN.closet.z0+HR_OFFICE_RUN.closet.z1)/2; // west door
HR_OFFICE_RUN.oval1WestDoorZ=HR_OFFICE_RUN.oval1.z1-3*FEET_TO_METERS;                 // south end west glass wall
HR_OFFICE_RUN.oval1EastPlantDoorZ=HR_OFFICE_RUN.oval1.z1-3*FEET_TO_METERS;            // south end east wall into plant
HR_OFFICE_RUN.oval2EastPlantDoorZ=HR_OFFICE_RUN.oval2.z0+3*FEET_TO_METERS;            // north end east wall into plant
HR_OFFICE_RUN.oval2WestDoorZ=HR_OFFICE_RUN.oval2.z1-3*FEET_TO_METERS;                 // south end west wall
HR_OFFICE_RUN.smallWestDoorZ=HR_OFFICE_RUN.small.z1-3*FEET_TO_METERS;                 // southern west wall door
HR_OFFICE_RUN.secondLastWestDoorZ=HR_OFFICE_RUN.secondLast.z1-3*FEET_TO_METERS;       // southern west wall door
HR_OFFICE_RUN.centerSouthDoorX0=(HR_OFFICE_RUN.x0+HR_OFFICE_RUN.x1)/2-HR_OFFICE_RUN.southDoorW/2;
HR_OFFICE_RUN.centerSouthDoorX1=(HR_OFFICE_RUN.x0+HR_OFFICE_RUN.x1)/2+HR_OFFICE_RUN.southDoorW/2;

// South of the last measured office: a 3-office east-west run.
// Start 20 px south of the last office south wall, depth 50 px north-south.
// Two north-south divider walls sit 42 px and 75 px from the plant wall.
const HR_EW_OFFICES={
  x0:HR_OFFICE.x0,
  x1:HR_OFFICE.x1,
  z0:HR_OFFICE_RUN.last.z1 + (20/2.95)*FEET_TO_METERS,
  z1:HR_OFFICE_RUN.last.z1 + ((20+50)/2.95)*FEET_TO_METERS,
  div1X:HR_OFFICE.x1 - (42/2.95)*FEET_TO_METERS,
  div2X:HR_OFFICE.x1 - (75/2.95)*FEET_TO_METERS
};
// Interior plant wall running along the west side of the main plant.
// It stays on the plant side of x=0 and leaves the patio doorway open.
const WEST_INTERIOR_PLANT_WALL={
  x:0,
  z0:0,
  z1:PLANT_DEPTH_METERS,
  doorZ0:WEST_PATIO_DOOR_Z-WEST_PATIO_DOOR_W/2,
  doorZ1:WEST_PATIO_DOOR_Z+WEST_PATIO_DOOR_W/2
};
// West-wall lockers inside the plant: start 10ft south of the patio door and run south.
// Treat the original 8 locker banks as one full section, then repeat that section twice more to the south.
const WEST_WALL_LOCKERS={
  x0:0.15*FEET_TO_METERS,
  x1:1.65*FEET_TO_METERS,
  z0:WEST_INTERIOR_PLANT_WALL.doorZ1+10*FEET_TO_METERS,
  sectionD:4*FEET_TO_METERS,
  gap:0.5*FEET_TO_METERS,
  sectionsPerGroup:8,
  groupCount:4,
  groupGap:2*FEET_TO_METERS,
  tierH:3.25*FEET_TO_METERS,
  totalH:6.5*FEET_TO_METERS,
  colsPerSection:3
};
WEST_WALL_LOCKERS.groupSpan = WEST_WALL_LOCKERS.sectionsPerGroup*WEST_WALL_LOCKERS.sectionD + (WEST_WALL_LOCKERS.sectionsPerGroup-1)*WEST_WALL_LOCKERS.gap;
WEST_WALL_LOCKERS.z1 = WEST_WALL_LOCKERS.z0 + WEST_WALL_LOCKERS.groupCount*WEST_WALL_LOCKERS.groupSpan + (WEST_WALL_LOCKERS.groupCount-1)*WEST_WALL_LOCKERS.groupGap;
const getWestLockerSectionZ0=(groupIndex,sectionIndex)=>WEST_WALL_LOCKERS.z0 + groupIndex*(WEST_WALL_LOCKERS.groupSpan+WEST_WALL_LOCKERS.groupGap) + sectionIndex*(WEST_WALL_LOCKERS.sectionD+WEST_WALL_LOCKERS.gap);
const WORLD_X0=Math.min(0,HR_OFFICE.x0), WORLD_X1=PLANT_WIDTH_METERS, WORLD_Z0=0, WORLD_Z1=PLANT_DEPTH_METERS;
const WORLD_CX=(WORLD_X0+WORLD_X1)/2, WORLD_CZ=(WORLD_Z0+WORLD_Z1)/2;



/*
╔══════════════════════════════════════════════════════════════╗
║ LESSON 04 — ENGINE SETUP IS ONE LAYER                        ║
╚══════════════════════════════════════════════════════════════╝

The renderer, scene, camera, controls, lighting, and XR setup are engine setup.
They are allowed to use Three.js language directly because this is the boundary
where the app opens the sealed engine.

After this layer, plant-specific code should return to plant language.
*/

// ── SCENE ──────────────────────────────────────────────────────────────────
const canvas=document.getElementById('c');
const renderer=new THREE.WebGLRenderer({canvas,antialias:true,powerPreference:'high-performance'});
renderer.setPixelRatio(Math.min(devicePixelRatio,1.5)); // cap DPR — full retina ×2 is brutal on tablet GPUs
renderer.xr.enabled=true;
renderer.shadowMap.enabled=true;
renderer.shadowMap.type=THREE.PCFSoftShadowMap;
renderer.toneMapping=THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure=1.2;
const vrButton=VRButton.createButton(renderer);
vrButton.title='Enter VR / WebXR mode';
vrButton.setAttribute('aria-label','Enter VR / WebXR mode');
document.body.appendChild(vrButton);
const scene=new THREE.Scene();
scene.background=new THREE.Color(0x16191d);
scene.fog=new THREE.Fog(0x16191d,1200,3000); // depth haze; starts beyond top-down view distance
// ── LIGHTING ───────────────────────────────────────────────────────────────
// Image-based ambient — gives PBR materials real reflections instead of flat ambient grey
const pmrem=new THREE.PMREMGenerator(renderer);
scene.environment=pmrem.fromScene(new RoomEnvironment(),0.04).texture;
scene.environmentIntensity=0.45;
pmrem.dispose();

const hemiLight=new THREE.HemisphereLight(0xbfd4e6,0x44403a,0.45); // cool sky / warm concrete bounce
scene.add(hemiLight);

const sunLight=new THREE.DirectionalLight(0xfff2e0,1.3);
sunLight.position.set(WORLD_CX+220,380,WORLD_CZ-260);
sunLight.target.position.set(WORLD_CX,0,WORLD_CZ);
scene.add(sunLight.target);
sunLight.castShadow=true;
// Shadow frustum fitted to the actual plant footprint — sharper shadows at 1/4 the memory
sunLight.shadow.mapSize.width=2048;
sunLight.shadow.mapSize.height=2048;
const shadowR=Math.hypot(PLANT_WIDTH_METERS,PLANT_DEPTH_METERS)*0.55;
sunLight.shadow.camera.left=-shadowR;
sunLight.shadow.camera.right=shadowR;
sunLight.shadow.camera.top=shadowR;
sunLight.shadow.camera.bottom=-shadowR;
sunLight.shadow.camera.near=50;
sunLight.shadow.camera.far=1200;
sunLight.shadow.bias=-0.0004;
scene.add(sunLight);

// Fill light for better volume
const fillLight=new THREE.PointLight(0x4f98a3,0.4);
fillLight.position.set(WORLD_CX,200,WORLD_CZ);
scene.add(fillLight);


const camera=new THREE.PerspectiveCamera(42,1,0.1,3000);
const controls=new OrbitControls(camera,canvas);
controls.enableDamping=true; controls.dampingFactor=0.07;
controls.maxPolarAngle=Math.PI/2.01;
controls.minDistance=5; controls.maxDistance=2000;
const keys=new Set();

/*
╔══════════════════════════════════════════════════════════════╗
║ LESSON 05 — INPUT SHOULD CHANGE STATE, NOT GEOMETRY          ║
╚══════════════════════════════════════════════════════════════╝

Touch controls, keyboard controls, menu buttons, and VR controls should all ask
for movement or view changes. They should not each implement their own version
of the plant rules.
*/

// -- MOBILE TOUCH CONTROLS -- on-screen joysticks, capability-detected --
const IS_MOBILE=/iPhone|iPad|iPod|Android/i.test(navigator.userAgent)||(navigator.maxTouchPoints>1);
const moveState={fwd:0,side:0};
const lookState={yaw:0,pitch:0};
const JOY_TURN=1.8; // rad/s at full look-stick deflection
function setupJoystick(id,onMove){
  const el=document.getElementById(id);
  const knob=el.querySelector('.joystick-knob');
  let touchId=null;
  const apply=(t)=>{
    const r=el.getBoundingClientRect();
    let dx=t.clientX-(r.left+r.width/2), dy=t.clientY-(r.top+r.height/2);
    const dist=Math.min(60,Math.hypot(dx,dy)), a=Math.atan2(dy,dx);
    dx=Math.cos(a)*dist; dy=Math.sin(a)*dist;
    knob.style.transform=`translate(calc(-50% + ${dx}px), calc(-50% + ${dy}px))`;
    onMove(dx/60,dy/60);
  };
  const reset=()=>{ touchId=null; knob.style.transform='translate(-50%,-50%)'; onMove(0,0); };
  el.addEventListener('touchstart',e=>{ if(touchId!==null)return; const t=e.changedTouches[0]; touchId=t.identifier; apply(t); e.preventDefault(); },{passive:false});
  el.addEventListener('touchmove',e=>{ if(touchId===null)return; for(const t of e.changedTouches){ if(t.identifier===touchId){ apply(t); e.preventDefault(); return; } } },{passive:false});
  const end=e=>{ if(touchId===null)return; for(const t of e.changedTouches){ if(t.identifier===touchId){ reset(); return; } } };
  el.addEventListener('touchend',end);
  el.addEventListener('touchcancel',end);
}
if(IS_MOBILE){
  document.getElementById('moveJoystick').style.display='block';
  document.getElementById('lookJoystick').style.display='block';
  document.getElementById('mobileControls').style.display='flex';
  setupJoystick('moveJoystick',(x,y)=>{moveState.side=x;moveState.fwd=-y;});
  setupJoystick('lookJoystick',(x,y)=>{lookState.yaw=x;lookState.pitch=-y;});
}
let viewMode='orbit';
// On-demand rendering — only draw frames when something actually changed
let needsRender=true;
const invalidate=()=>{needsRender=true;};
controls.addEventListener('change',invalidate);

let camMode=1; // 1 = first person (cab), 2 = second person (facing the lift), 3 = third person (chase)
// ── ON FOOT vs MOUNTED ──
const FOOT_EYE=1.7, FOOT_SPEED=3.4, FOOT_SPRINT=8.5;
const CAB_EYE_BACK=0.52; // m — driver's eye behind the lift origin: over the seat cushion (z 0.42), in front of the seat back (z 0.61)
let mounted=false;
const liftState={pos:new THREE.Vector3(74*FEET_TO_METERS,0,33*FEET_TO_METERS),yaw:-Math.PI/2}; // parked in a west parking stall
const MOUNT_RANGE=3.5;

/*
╔══════════════════════════════════════════════════════════════╗
║ LESSON 06 — ONE GATEKEEPER FOR EVERY VIEW CHANGE             ║
╚══════════════════════════════════════════════════════════════╝

Every named view and walk start passes through setView().

This prevents the app from having one camera method for the menu, a second for
mobile, a third for keyboard shortcuts, and a fourth for future VR changes.
Same result should mean same path.
*/

function setView(requestedView){
  if(requestedView&&requestedView.startsWith('walk')){
    // Named walk starts are first-person spawn points.
    // walk2 / walk3 still act as camera-mode changes while mounted or already walking.
    const namedSpawn=(requestedView==='walk1'||requestedView==='walkMatt'||requestedView==='walkWh2Office');
    camMode=(requestedView==='walk2'||requestedView==='walk3')?(parseInt(requestedView.slice(4))||1):1;
    if(viewMode!=='walk'){
      viewMode='walk';
      controls.enabled=false;
      camera.fov=75; camera.updateProjectionMatrix();
    }
    if(viewMode==='walk'&&namedSpawn){
      mounted=false;
      if(requestedView==='walkMatt'){
        // Matt's Office: third office from the south of the first HR office run.
        const spawnOffice=HR_OFFICE_RUN.small;
        walk.pos.set((spawnOffice.x0+spawnOffice.x1)/2+3*FEET_TO_METERS, FOOT_EYE, (spawnOffice.z0+spawnOffice.z1)/2);
        walk.yaw=Math.PI/2; // seated behind desk, facing west
      } else if(requestedView==='walkWh2Office'&&rawGoodsOffice){
        // Ira's Office desk.
        walk.pos.set(rawGoodsOffice.x1-3*FEET_TO_METERS, FOOT_EYE, (rawGoodsOffice.z0+rawGoodsOffice.z1)/2);
        walk.yaw=Math.PI/2; // facing west from the desk
      } else {
        // Default 1st-person walk starts in the Shipping Office.
        walk.pos.set(SHIP_OFFICE.x1-5*FEET_TO_METERS, FOOT_EYE, SHIP_OFFICE.z0+10*FEET_TO_METERS);
        walk.yaw=Math.PI/2; // facing west inside shipping office
      }
      walk.pitch=0;
    }
    updateWalkCamera();
    invalidate();
    if(!IS_MOBILE) canvas.requestPointerLock();
    return;
  }
  if(document.pointerLockElement===canvas) document.exitPointerLock();
  camera.fov=42; camera.updateProjectionMatrix();
  viewMode='orbit';
  controls.enabled=true;
  const plantCenterX=WORLD_CX,plantCenterZ=WORLD_CZ;
  const orbitCameraPresets={
    top:[plantCenterX,1100,plantCenterZ,plantCenterX,0,plantCenterZ],
    iso:[plantCenterX-150,600,plantCenterZ+500,plantCenterX,0,plantCenterZ],
    north:[plantCenterX,180,plantCenterZ+850,plantCenterX,0,plantCenterZ]
  };
  const [eyeX,eyeY,eyeZ,targetX,targetY,targetZ]=orbitCameraPresets[requestedView]||orbitCameraPresets.top;
  camera.position.set(eyeX,eyeY,eyeZ); controls.target.set(targetX,targetY,targetZ); controls.update();
  invalidate();
}
setView('top');
document.getElementById('vsel').addEventListener('change',e=>setView(e.target.value));

// ── FLOOR CANVAS ───────────────────────────────────────────────────────────
// One surface. Everything painted here — zones, lines, columns.
// 2 pixels per foot gives adequate resolution without blowing memory.

/*
╔══════════════════════════════════════════════════════════════╗
║ LESSON 07 — FLOOR PAINT USES ITS OWN CONSISTENT LANGUAGE     ║
╚══════════════════════════════════════════════════════════════╝

The floor texture is a 2D drafting surface that later becomes a 3D material.

Because this is not ordinary DOM canvas art, every helper name says its unit:
meters in, floor pixels out. That removes the old patchwork shorthand.
*/

const FLOOR_PIXELS_PER_FOOT = 2;
const FLOOR_CANVAS_WIDTH = Math.ceil(PLANT_WIDTH_METERS / FEET_TO_METERS) * FLOOR_PIXELS_PER_FOOT;
const FLOOR_CANVAS_HEIGHT = Math.ceil(PLANT_DEPTH_METERS / FEET_TO_METERS) * FLOOR_PIXELS_PER_FOOT;
const floorPaintCanvas = document.createElement('canvas');
floorPaintCanvas.width = FLOOR_CANVAS_WIDTH;
floorPaintCanvas.height = FLOOR_CANVAS_HEIGHT;
const floorPaintContext = floorPaintCanvas.getContext('2d');

// world metres → canvas pixels
const metersToFloorPixels = meters => (meters / FEET_TO_METERS) * FLOOR_PIXELS_PER_FOOT;
const LINE_WIDTH_PIXELS = Math.max(1.5, metersToFloorPixels(LINE_WIDTH_METERS)); // 4in line, minimum 1.5px visible

// primitives
function fillFloorRectMeters(x0, z0, x1, z1) {
  floorPaintContext.fillRect(
    metersToFloorPixels(x0),
    metersToFloorPixels(z0),
    metersToFloorPixels(x1 - x0),
    metersToFloorPixels(z1 - z0)
  );
}
function drawHorizontalFloorLineMeters(z, x0, x1, widthPixels = LINE_WIDTH_PIXELS) {
  floorPaintContext.fillRect(
    metersToFloorPixels(x0),
    metersToFloorPixels(z) - widthPixels / 2,
    metersToFloorPixels(x1 - x0),
    widthPixels
  );
}
function drawVerticalFloorLineMeters(x, z0, z1, widthPixels = LINE_WIDTH_PIXELS) {
  floorPaintContext.fillRect(
    metersToFloorPixels(x) - widthPixels / 2,
    metersToFloorPixels(z0),
    widthPixels,
    metersToFloorPixels(z1 - z0)
  );
}
function drawFloorText(text,x,z,angle=0,sizeFt=2.8,strokeWFt=0.18){
  floorPaintContext.save();
  floorPaintContext.translate(metersToFloorPixels(x),metersToFloorPixels(z));
  floorPaintContext.rotate(angle);
  floorPaintContext.font=`900 ${metersToFloorPixels(sizeFt*FEET_TO_METERS)}px Arial, sans-serif`;
  floorPaintContext.textAlign='center';
  floorPaintContext.textBaseline='middle';
  floorPaintContext.lineWidth=Math.max(1,metersToFloorPixels(strokeWFt*FEET_TO_METERS));
  floorPaintContext.strokeStyle='rgba(0,0,0,0.75)';
  floorPaintContext.fillStyle='#ffffff';
  floorPaintContext.strokeText(text,0,0);
  floorPaintContext.fillText(text,0,0);
  floorPaintContext.restore();
}

// ── PAINT: BASE CONCRETE ───────────────────────────────────────────────────
floorPaintContext.fillStyle='#999999';
floorPaintContext.fillRect(0,0,FLOOR_CANVAS_WIDTH,FLOOR_CANVAS_HEIGHT);
// Add concrete noise/texture
for(let i=0;i<200000;i++){
  const x=Math.random()*FLOOR_CANVAS_WIDTH, y=Math.random()*FLOOR_CANVAS_HEIGHT;
  const s=Math.random()*2+1;
  const v=Math.floor(Math.random()*30-15);
  floorPaintContext.fillStyle=`rgba(${150+v},${150+v},${150+v},0.08)`;
  floorPaintContext.fillRect(x,y,s,s);
}
// Add some larger concrete "splotches"
for(let i=0;i<800;i++){
  const x=Math.random()*FLOOR_CANVAS_WIDTH, y=Math.random()*FLOOR_CANVAS_HEIGHT;
  const r=Math.random()*30+10;
  const v=Math.floor(Math.random()*20-10);
  floorPaintContext.fillStyle=`rgba(${140+v},${140+v},${140+v},0.04)`;
  floorPaintContext.beginPath(); floorPaintContext.arc(x,y,r,0,Math.PI*2); floorPaintContext.fill();
}
// Add floor cracks and expansion joints
floorPaintContext.strokeStyle='rgba(60,60,60,0.1)';
floorPaintContext.lineWidth=0.5;
for(let i=0;i<20;i++){
  const x=Math.random()*FLOOR_CANVAS_WIDTH;
  floorPaintContext.beginPath(); floorPaintContext.moveTo(x,0); floorPaintContext.lineTo(x,FLOOR_CANVAS_HEIGHT); floorPaintContext.stroke();
}
for(let i=0;i<20;i++){
  const y=Math.random()*FLOOR_CANVAS_HEIGHT;
  floorPaintContext.beginPath(); floorPaintContext.moveTo(0,y); floorPaintContext.lineTo(FLOOR_CANVAS_WIDTH,y); floorPaintContext.stroke();
}

// ── PAINT: ZONE TINTS ──────────────────────────────────────────────────────
floorPaintContext.fillStyle='rgba(170,119,34,0.14)';  fillFloorRectMeters(PLANT_REGIONS.WH2_L,0,WH23_DIV_X,PLANT_DEPTH_METERS);
floorPaintContext.fillStyle='rgba(122,58,170,0.14)';  fillFloorRectMeters(WH23_DIV_X,0,PLANT_REGIONS.WH3_R,PLANT_DEPTH_METERS);
// North void zone + walkways
floorPaintContext.fillStyle='rgba(28,28,42,0.68)';    fillFloorRectMeters(PLANT_REGIONS.VOID_L,VOID_NORTH_ZS,PLANT_REGIONS.VOID_R,VOID_NORTH_ZE);
floorPaintContext.fillStyle='#1255a4';
fillFloorRectMeters(PLANT_REGIONS.J_R,   VOID_NORTH_ZS,PLANT_REGIONS.VOID_L,VOID_NORTH_ZE);
fillFloorRectMeters(PLANT_REGIONS.VOID_R,VOID_NORTH_ZS,PLANT_REGIONS.WH2_L,VOID_NORTH_ZE);
floorPaintContext.fillStyle='#ffffff';
drawVerticalFloorLineMeters(PLANT_REGIONS.J_R,   VOID_NORTH_ZS,VOID_NORTH_ZE);
drawVerticalFloorLineMeters(PLANT_REGIONS.WH2_L, VOID_NORTH_ZS,VOID_NORTH_ZE);
drawHorizontalFloorLineMeters(VOID_NORTH_ZE,108*FEET_TO_METERS,PLANT_REGIONS.VOID_L); // white 4in line west from void south wall to parking rail
floorPaintContext.fillStyle='rgba(28,28,42,0.68)';    fillFloorRectMeters(PLANT_REGIONS.VOID_L,J_ZS,PLANT_REGIONS.VOID_R,J_ZS+J_NS);
// Plastipak blue walkways — west freed space (J_R→VOID_L) + east freed space (VOID_R→WH2_L)
floorPaintContext.fillStyle='#1255a4';
fillFloorRectMeters(PLANT_REGIONS.J_R,  J_ZS,PLANT_REGIONS.VOID_L,J_ZE);   // west walkway: 543–551ft
fillFloorRectMeters(PLANT_REGIONS.VOID_R,J_ZS,PLANT_REGIONS.WH2_L,J_ZE);   // east walkway: 608–617ft
floorPaintContext.fillStyle='#ffffff';
drawVerticalFloorLineMeters(PLANT_REGIONS.J_R,   J_ZS,J_ZE);              // west outer border
