/*
╔══════════════════════════════════════════════════════════════╗
║ LESSON 09 — REPEATED ROWS USE ONE REGISTRATION METHOD        ║
╚══════════════════════════════════════════════════════════════╝

Sequential paired rows should not be recreated by hand for each row.

When the pattern is the same, the method is the same. When the floor breaks the
pattern, the exception must be named near the exception.
*/

function registerSequentialPairRowBins(row,x0,x1,zS,zE,startNo,endNo,section){
  const ids=[];
  for(let n=startNo;n<=endNo;n++) ids.push(`${row}${String(n).padStart(2,'0')}`);
  const cycle=580*INCHES_TO_METERS;
  const lineOffsets=[2,102,202,210,310,410,418,518,570].map(o=>o*INCHES_TO_METERS);
  const lines=[];
  const c0=Math.floor((zS-zS)/cycle)-1;
  const c1=Math.ceil((zE-zS)/cycle)+1;
  for(let c=c0;c<=c1;c++){
    const base=zS+c*cycle;
    for(const off of lineOffsets){
      const z=base+off;
      if(z>zS-0.001&&z<zE+0.001) lines.push(z);
    }
  }
  lines.sort((a,b)=>a-b);
  let idx=0;
  for(let i=0;i<lines.length-1&&idx<ids.length;i++){
    const z0=lines[i], z1=lines[i+1], depth=z1-z0;
    if(depth<48*INCHES_TO_METERS-0.001||depth>104*INCHES_TO_METERS+0.001) continue;
    registerBinQuad({
      id:ids[idx++],
      row,
      x0,x1,z0,z1,
      type:depth<70*INCHES_TO_METERS?'slim':'regular',
      section
    });
  }
}
