// High-res floor label planes — floor canvas is 2px/ft (too coarse at eye level).
// scale(1,-1) on canvas corrects letter-top orientation after the mesh rotation.
function addLaneLabel(text,x,z,faceEast){
  const cw=512,ch=128;
  const cv=document.createElement('canvas');
  cv.width=cw; cv.height=ch;
  const c=cv.getContext('2d');
  c.clearRect(0,0,cw,ch);
  c.save();
  c.translate(cw/2,ch/2);
  c.font=`900 ${Math.round(ch*0.68)}px Arial,sans-serif`;
  c.textAlign='center';
  c.textBaseline='middle';
  c.lineWidth=3;
  c.strokeStyle='rgba(0,0,0,0.88)';
  c.fillStyle='#ffffff';
  c.strokeText(text,0,0);
  c.fillText(text,0,0);
  c.restore();
  const tex=new THREE.CanvasTexture(cv);
  tex.colorSpace=THREE.SRGBColorSpace;
  const mesh=new THREE.Mesh(
    new THREE.PlaneGeometry(3*FEET_TO_METERS,0.75*FEET_TO_METERS),
    new THREE.MeshBasicMaterial({map:tex,transparent:true,depthWrite:false})
  );
  mesh.position.set(x,0.005,z);
  mesh.rotation.x=-Math.PI/2;
  mesh.rotation.z=faceEast?-Math.PI/2:Math.PI/2;
  scene.add(mesh);
}
function addMaterialSquareFloorPaint(text,x0,z0,w,d){
  const cw=2048,ch=2048;
  const cv=document.createElement('canvas');
  cv.width=cw; cv.height=ch;
  const c=cv.getContext('2d');
  c.clearRect(0,0,cw,ch);
  const lines=String(text).split('\n');
  const fontPx=Math.round(ch*(lines.length>1?0.145:0.19));
  const lineGap=fontPx*0.98;
  c.font=`900 ${fontPx}px Arial,sans-serif`;
  c.textAlign='center';
  c.textBaseline='middle';
  c.fillStyle='#ffffff';
  c.save();
  c.translate(cw/2,ch/2);
  c.rotate(Math.PI/2);
  const y0=ch/2-(lines.length-1)*lineGap/2+2;
  lines.forEach((line,i)=>{
    c.fillText(line,0,y0+i*lineGap-ch/2);
  });
  c.restore();
  const tex=new THREE.CanvasTexture(cv);
  tex.colorSpace=THREE.SRGBColorSpace;
  tex.generateMipmaps=false;
  tex.minFilter=THREE.LinearFilter;
  tex.magFilter=THREE.LinearFilter;
  const mesh=new THREE.Mesh(
    new THREE.PlaneGeometry(w,d),
    new THREE.MeshBasicMaterial({
      map:tex,
      transparent:true,
      alphaTest:0.02,
      depthWrite:false,
      side:THREE.DoubleSide,
      polygonOffset:true,
      polygonOffsetFactor:-2,
      polygonOffsetUnits:-2
    })
  );
  mesh.position.set(x0+w/2,0.022,z0+d/2);
  mesh.rotation.x=-Math.PI/2;
  mesh.renderOrder=24;
  scene.add(mesh);
}
function addMaterialSquareOutline(x0,z0,w,d){
  const mat=new THREE.MeshBasicMaterial({
    color:0xffcc00,
    depthWrite:false,
    side:THREE.DoubleSide,
    polygonOffset:true,
    polygonOffsetFactor:-4,
    polygonOffsetUnits:-4
  });
  const y=0.028, t=4*INCHES_TO_METERS;
  const addStrip=(cx,cz,sx,sz)=>{
    const mesh=new THREE.Mesh(new THREE.PlaneGeometry(sx,sz),mat);
    mesh.position.set(cx,y,cz);
    mesh.rotation.x=-Math.PI/2;
    mesh.renderOrder=26;
    scene.add(mesh);
  };
  addStrip(x0+w/2,z0,w,t);
  addStrip(x0+w/2,z0+d,w,t);
  addStrip(x0,z0+d/2,t,d);
  addStrip(x0+w,z0+d/2,t,d);
}
