/*
╔══════════════════════════════════════════════════════════════╗
║ LESSON 10 — WAREHOUSE 3 USES A REUSABLE LANE BUILDER         ║
╚══════════════════════════════════════════════════════════════╝

WH3 has repeated floor-bin columns with direction, tails, and pitch.

This function exists so that repeated lane logic stays in one place. The row
call supplies the facts; the builder handles the repeated method.
*/

function drawWh3FloorBins(xL,xR,count,startZ,dir,opt={}){
  const perBay=6, pitch=94*INCHES_TO_METERS, colStep=580*INCHES_TO_METERS, colHalf=6*INCHES_TO_METERS, firstCol=BIN_N+576*INCHES_TO_METERS;
  const colAtOrBefore=z=>firstCol+Math.floor((z-firstCol)/colStep)*colStep;
  const colAtOrAfter=z=>firstCol+Math.ceil((z-firstCol)/colStep)*colStep;
  let remaining=count;
  let colN=dir>0?colAtOrBefore(startZ):colAtOrAfter(startZ)-colStep;
  const lanes=[];
  while(remaining>0){
    const n=Math.min(perBay,remaining);
    const colS=colN+colStep;
    const availN=colN+colHalf, availS=colS-colHalf;
    const margin=(availS-availN-n*pitch)/2;
    const isTail=remaining<=perBay&&n<perBay;
    let groupN=availN+margin;
    if(isTail&&opt.tail==='north') groupN=availN;
    if(isTail&&opt.tail==='south') groupN=availS-n*pitch;
    const groupS=groupN+n*pitch;
    drawVerticalFloorLineMeters(xL,groupN,groupS); drawVerticalFloorLineMeters(xR,groupN,groupS);
    for(let i=0;i<=n;i++) drawHorizontalFloorLineMeters(groupN+i*pitch,xL,xR);
    for(let i=0;i<n;i++) lanes.push({z0:groupN+i*pitch,z1:groupN+(i+1)*pitch});
    remaining-=n;
    colN+=dir>0?colStep:-colStep;
  }
  return lanes;
}
function wh3ColumnGroupStart(startZ,dir,groupIndex){
  const pitch=94*INCHES_TO_METERS, colStep=580*INCHES_TO_METERS, colHalf=6*INCHES_TO_METERS, firstCol=BIN_N+576*INCHES_TO_METERS;
  const colAtOrBefore=z=>firstCol+Math.floor((z-firstCol)/colStep)*colStep;
  const colAtOrAfter=z=>firstCol+Math.ceil((z-firstCol)/colStep)*colStep;
  const baseColN=dir>0?colAtOrBefore(startZ):colAtOrAfter(startZ)-colStep;
  const colN=baseColN+(dir>0?groupIndex:-groupIndex)*colStep;
  const availN=colN+colHalf, availS=colN+colStep-colHalf;
  return availN+(availS-availN-6*pitch)/2;
}
const wh3WestWallSpans=[];
let wh3LastRowWallSpan=null;
function drawWh3WestFloorBins(xL,xR){
  const pitch=94*INCHES_TO_METERS, colStep=580*INCHES_TO_METERS, colHalf=6*INCHES_TO_METERS, firstCol=BIN_N+576*INCHES_TO_METERS;
  const lanes=[];
  const drawGroup=(groupN,n)=>{
    const groupS=groupN+n*pitch;
    drawVerticalFloorLineMeters(xL,groupN,groupS); drawVerticalFloorLineMeters(xR,groupN,groupS);
    for(let i=0;i<=n;i++) drawHorizontalFloorLineMeters(groupN+i*pitch,xL,xR);
    for(let i=0;i<n;i++) lanes.push({z0:groupN+i*pitch,z1:groupN+(i+1)*pitch});
    wh3WestWallSpans.push([groupN,groupS]);
  };
  let colN=firstCol+6*colStep;
  let availN=colN+colHalf, availS=colN+colStep-colHalf;
  drawGroup(availN+2*pitch,1);
  for(let g=0;g<6;g++){
    colN=firstCol+(5-g)*colStep;
    availN=colN+colHalf; availS=colN+colStep-colHalf;
    drawGroup(availN+(availS-availN-6*pitch)/2,6);
  }
  return lanes;
}
function drawWh3ExplicitLanes(xL,xR,lanes){
  if(!lanes.length) return;
  const z0=Math.min(...lanes.map(l=>l.z0));
  const z1=Math.max(...lanes.map(l=>l.z1));
  drawVerticalFloorLineMeters(xL,z0,z1); drawVerticalFloorLineMeters(xR,z0,z1);
  const lines=[...new Set(lanes.flatMap(l=>[l.z0,l.z1]).map(z=>Math.round(z*10000)/10000))]
    .sort((a,b)=>a-b);
  lines.forEach(z=>drawHorizontalFloorLineMeters(z,xL,xR));
}
function registerWh3Lanes(row,lanes,x0,x1,section,start=1){
  lanes.forEach((lane,i)=>{
    const id=`${row}${String(start+i).padStart(2,'0')}`;
    registerBinQuad({
      id,
      row,
      x0,
      x1,
      z0:lane.z0,
      z1:lane.z1,
      type:'regular',
      section
    });
  });
}
