    const chair=new THREE.Mesh(new THREE.BoxGeometry(2*FEET_TO_METERS,3*FEET_TO_METERS,2*FEET_TO_METERS),chairMat);
    chair.position.set(desk.position.x+2.25*FEET_TO_METERS,1.5*FEET_TO_METERS,desk.position.z);
