/*
╔══════════════════════════════════════════════════════════════╗
║ LESSON 11 — SEALED ASSET BECOMES A REAL OBJECT HERE          ║
╚══════════════════════════════════════════════════════════════╝

The base64 image above was only data.

This function turns it into a physical cab tablet with a screen, keyboard, arm,
position, shadows, and a fixed driver-facing angle.
*/

function createCabTablet(){
  const tabletGroup=new THREE.Group();
  const tabletBezelMaterial=new THREE.MeshStandardMaterial({color:0x111111,roughness:0.5});
  const tabletScreenCanvas=document.createElement('canvas'); tabletScreenCanvas.width=512; tabletScreenCanvas.height=320;
  const tabletScreenContext=tabletScreenCanvas.getContext('2d');
  tabletScreenContext.fillStyle='#0b1d2a'; tabletScreenContext.fillRect(0,0,tabletScreenCanvas.width,tabletScreenCanvas.height);
  const tabletScreenTexture=new THREE.CanvasTexture(tabletScreenCanvas); tabletScreenTexture.colorSpace=THREE.SRGBColorSpace;
  const screenImg=new Image();
  screenImg.onload=()=>{
    tabletScreenContext.clearRect(0,0,tabletScreenCanvas.width,tabletScreenCanvas.height);
    tabletScreenContext.drawImage(screenImg,0,0,tabletScreenCanvas.width,tabletScreenCanvas.height);
    tabletScreenTexture.needsUpdate=true;
  };
  screenImg.src=FORKLIFT_SCREEN_IMAGE;
  const body=new THREE.Mesh(new THREE.BoxGeometry(0.30,0.21,0.018),tabletBezelMaterial);
  const screen=new THREE.Mesh(new THREE.PlaneGeometry(0.272,0.182),new THREE.MeshBasicMaterial({map:tabletScreenTexture})); // self-lit
  screen.position.z=0.0095;
  const kbBase=new THREE.Mesh(new THREE.BoxGeometry(0.30,0.013,0.11),tabletBezelMaterial);
  kbBase.position.set(0,-0.135,0.045); kbBase.rotation.x=0.5;  // keys tilted toward the driver
  const keys=new THREE.Mesh(new THREE.BoxGeometry(0.27,0.008,0.085),new THREE.MeshStandardMaterial({color:0x2e3338,roughness:0.7}));
  keys.position.set(0,-0.128,0.047); keys.rotation.x=0.5;
  const arm=new THREE.Mesh(new THREE.BoxGeometry(0.03,0.03,0.14),new THREE.MeshStandardMaterial({color:0x46535f,roughness:0.5,metalness:0.4}));
  arm.position.set(0,0.10,-0.075);
  tabletGroup.add(body,screen,kbBase,keys,arm);
  tabletGroup.traverse(o=>{if(o.isMesh){o.castShadow=true;o.receiveShadow=true;}});
  tabletGroup.position.set(0.32,1.60,0.115);   // right side, 1ft forward of the seat — same height
  tabletGroup.rotation.set(0.32,-0.60,0);      // tilted down toward the driver's face
  return tabletGroup;
}

